import React from 'react';

export default function AutomataSVG({ automata, type, highlightPath = [] }) {
  if (!automata || !automata.states) {
    return (
      <div style={{ color: '#94a3b8', padding: '20px' }}>
        No automata generated
      </div>
    );
  }

  const states = automata.states;
  const radius = 28;
  const centerX = 300;
  const centerY = 180;
  const circleRadius = 120;

  // Position states in a circle
  const positions = {};
  states.forEach((state, i) => {
    const angle = (2 * Math.PI * i) / states.length;

    positions[state] = {
      x: centerX + circleRadius * Math.cos(angle),
      y: centerY + circleRadius * Math.sin(angle),
    };
  });

  const accepts = new Set(
    type === 'nfa'
      ? [automata.accept]
      : automata.accepts || []
  );

  const transitions = [];

  Object.entries(automata.transitions || {}).forEach(([from, trans]) => {
    Object.entries(trans).forEach(([symbol, to]) => {
      if (Array.isArray(to)) {
        to.forEach(dest => {
          transitions.push({ from, to: dest, symbol });
        });
      } else {
        transitions.push({ from, to, symbol });
      }
    });
  });

  return (
    <svg width="100%" height="400" viewBox="0 0 600 400">
      <defs>
        <marker
          id="arrow"
          markerWidth="10"
          markerHeight="10"
          refX="8"
          refY="3"
          orient="auto"
        >
          <polygon points="0 0, 10 3, 0 6" fill="#94a3b8" />
        </marker>
      </defs>

      {/* transitions */}
      {/* transitions */}
{/* transitions */}
{transitions.map((t, i) => {
  const from = positions[t.from];
  const to = positions[t.to];

  if (!from || !to) return null;

  const highlighted =
    highlightPath.includes(t.from) &&
    highlightPath.includes(t.to);

  const stroke = highlighted ? '#f59e0b' : '#94a3b8';

  // ───────────────── SELF LOOP ─────────────────
  if (t.from === t.to) {
    const loopTop = from.y - radius - 35;

    const path = `
      M ${from.x - 16} ${from.y - radius + 2}
      Q ${from.x} ${loopTop}
        ${from.x + 16} ${from.y - radius + 2}
    `;

    return (
      <g key={i}>
        <path
          d={path}
          fill="none"
          stroke={stroke}
          strokeWidth="2.5"
          markerEnd="url(#arrow)"
        />

        <text
          x={from.x}
          y={loopTop - 8}
          fill={symbolColor(t.symbol)}
          fontSize="13"
          textAnchor="middle"
        >
          {t.symbol}
        </text>
      </g>
    );
  }

  // ───────────────── NORMAL/CURVED ─────────────────
  const dx = to.x - from.x;
  const dy = to.y - from.y;

  const angle = Math.atan2(dy, dx);

  // edge starts/ends at circle border
  const startX = from.x + radius * Math.cos(angle);
  const startY = from.y + radius * Math.sin(angle);

  const endX = to.x - radius * Math.cos(angle);
  const endY = to.y - radius * Math.sin(angle);

  // check reverse edge
  const reverseExists = transitions.some(
    other =>
      other.from === t.to &&
      other.to === t.from
  );

  // midpoint
  const mx = (startX + endX) / 2;
  const my = (startY + endY) / 2;

  let path;
  let labelX = mx;
  let labelY = my - 10;

  // ───────── CURVED EDGE ─────────
  if (reverseExists) {
    const curveStrength = 42;

    // perpendicular vector
    const nx = -dy;
    const ny = dx;

    const len = Math.sqrt(nx * nx + ny * ny);

    const offsetX = (nx / len) * curveStrength;
    const offsetY = (ny / len) * curveStrength;

    const cx = mx + offsetX;
    const cy = my + offsetY;

    path = `M ${startX} ${startY} Q ${cx} ${cy} ${endX} ${endY}`;

    labelX = cx;
    labelY = cy - 8;

    return (
      <g key={i}>
        <path
          d={path}
          fill="none"
          stroke={stroke}
          strokeWidth="2.5"
          markerEnd="url(#arrow)"
        />

        <text
          x={labelX}
          y={labelY}
          fill={symbolColor(t.symbol)}
          fontSize="13"
          textAnchor="middle"
        >
          {t.symbol}
        </text>
      </g>
    );
  }

  // ───────── STRAIGHT EDGE ─────────
  path = `M ${startX} ${startY} L ${endX} ${endY}`;

  return (
    <g key={i}>
      <path
        d={path}
        fill="none"
        stroke={stroke}
        strokeWidth="2.5"
        markerEnd="url(#arrow)"
      />

      <text
        x={labelX}
        y={labelY}
        fill={symbolColor(t.symbol)}
        fontSize="13"
        textAnchor="middle"
      >
        {t.symbol}
      </text>
    </g>
  );
})}

      {/* states */}
      {states.map(state => {
        const pos = positions[state];

        const highlighted = highlightPath.includes(state);

        return (
          <g key={state}>
            {/* start arrow */}
            {state === automata.start && (
              <line
                x1={pos.x - 70}
                y1={pos.y}
                x2={pos.x - radius}
                y2={pos.y}
                stroke="#60a5fa"
                strokeWidth="3"
                markerEnd="url(#arrow)"
              />
            )}

            <circle
              cx={pos.x}
              cy={pos.y}
              r={radius}
              fill={highlighted ? 'rgba(245,158,11,0.15)' : '#0f172a'}
              stroke={highlighted ? '#f59e0b' : '#475569'}
              strokeWidth="3"
            />

            {accepts.has(state) && (
              <circle
                cx={pos.x}
                cy={pos.y}
                r={radius - 7}
                fill="none"
                stroke="#34d399"
                strokeWidth="2"
              />
            )}

            <text
              x={pos.x}
              y={pos.y + 5}
              fill="white"
              fontSize="16"
              textAnchor="middle"
              fontWeight="bold"
            >
              {state}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

function symbolColor(symbol) {
  if (symbol === 'ε') return '#a78bfa';
  return '#cbd5e1';
}
